248→void ULFPShopWidget::OnRelicButtonClicked()
249→{
250→	for (const auto& Pair : ButtonToRelicIndexMap)
251→	{
252→		if (Pair.Key && Pair.Key->IsHovered())
253→		{
254→			SelectedRelicIndex = Pair.Value;
255→			RefreshDetailPanel();
256→			return;
257→		}
258→	}
259→}
260→
261→void ULFPShopWidget::OnPurchaseClicked()
262→{
263→	if (!CachedGameInstance || !CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
264→	{
265→		return;
266→	}
267→
268→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
269→	if (CachedGameInstance->TryPurchaseRelic(Entry.RelicID, Entry.Price))
270→	{
271→		RefreshShopUI();
272→	}
273→}
274→
275→void ULFPShopWidget::OnCloseClicked()
276→{
277→	SetVisibility(ESlateVisibility::Collapsed);
278→	RemoveFromParent();
279→	OnClosed.Broadcast();
280→}
