 17→ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
 18→{
 19→	CameraOffset = FVector::ZeroVector;
 20→
 21→	// 创建世界地图编辑器组件
 22→	WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
