422→void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
423→{
424→	if (!Node) return;
425→
426→	UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
427→
428→	switch (Node->NodeType)
429→	{
430→	case ELFPWorldNodeType::WNT_Battle:
431→	case ELFPWorldNodeType::WNT_Boss:
432→		EnterBattle(Node);
433→		break;
434→
435→	case ELFPWorldNodeType::WNT_Event:
436→		// TODO: 触发事件系统
437→		UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
438→		break;
439→
440→	case ELFPWorldNodeType::WNT_Shop:
441→		OpenShop(Node, false);
442→		break;
443→
444→	case ELFPWorldNodeType::WNT_Town:
445→		OpenTown(Node);
446→		break;
447→
448→	case ELFPWorldNodeType::WNT_QuestNPC:
449→		// TODO: 触发任务对话
450→		UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
451→		break;
452→
453→	case ELFPWorldNodeType::WNT_SkillNode:
454→		// TODO: 打开技能树 UI
455→		UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
456→		break;
457→
458→	case ELFPWorldNodeType::WNT_EvolutionTower:
459→		OpenEvolutionTower();
460→		break;
461→
462→	default:
463→		break;
464→	}
465→}
