651→void ALFPWorldMapPlayerController::OpenTown(ALFPWorldMapNode* TownNode)
652→{
653→	if (!TownNode || !TownWidgetClass) return;
654→
655→	// 解析建筑列表
656→	TArray<ELFPTownBuildingType> BuildingTypes = LFPTownUtils::ParseBuildingList(TownNode->TownBuildingList);
