658→	if (BuildingTypes.Num() == 0)
659→	{
660→		UE_LOG(LogTemp, Warning, TEXT("城镇节点 %d: 建筑列表为空"), TownNode->NodeID);
661→		return;
662→	}
663→
664→	// 创建或显示 TownWidget
665→	if (!TownWidget)
666→	{
667→		TownWidget = CreateWidget<ULFPTownWidget>(this, TownWidgetClass);
668→		if (TownWidget)
669→		{
670→			TownWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnTownWidgetClosed);
671→			TownWidget->OnBuildingRequested.AddDynamic(this, &ALFPWorldMapPlayerController::OnTownBuildingRequested);
672→			TownWidget->AddToViewport();
673→		}
674→	}
675→	else
676→	{
677→		TownWidget->SetVisibility(ESlateVisibility::Visible);
678→		TownWidget->AddToViewport();
679→	}
680→
681→	if (TownWidget)
682→	{
683→		TownWidget->Setup(BuildingTypes);
684→	}
685→
686→	UE_LOG(LogTemp, Log, TEXT("城镇节点 %d: 打开城镇面板，建筑数量 %d"), TownNode->NodeID, BuildingTypes.Num());
687→}
