694→void ALFPWorldMapPlayerController::OnTownBuildingRequested(ELFPTownBuildingType BuildingType)
695→{
696→	UE_LOG(LogTemp, Log, TEXT("城镇: 请求打开建筑 %s"), *LFPTownUtils::BuildingTypeToString(BuildingType));
