 81→void ALFPWorldMapNode::UpdateVisualState()
 82→{
 83→	if (!NodeVisualData || !NodeSpriteComponent) return;
 84→
 85→	// 未揭开 → 显示迷雾精灵（如果有）
 86→	if (!bIsRevealed && NodeVisualData->FogSprite)
 87→	{
 88→		NodeSpriteComponent->SetSprite(NodeVisualData->FogSprite);
 89→		return;
 90→	}
 91→
 92→	// 已触发 → 显示已触发精灵（如果有）
 93→	if (bHasBeenTriggered && NodeVisualData->TriggeredSprite)
 94→	{
 95→		NodeSpriteComponent->SetSprite(NodeVisualData->TriggeredSprite);
 96→		return;
 97→	}
 98→
 99→	// 默认精灵
100→	NodeSpriteComponent->SetSprite(NodeVisualData->DefaultSprite);
101→}
