168→void ULFPWorldMapEditorComponent::HandleEdgeConnection(ALFPWorldMapNode* Node)
169→{
170→	if (!Node) return;
171→
172→	ALFPWorldMapManager* Manager = GetWorldMapManager();
173→	if (!Manager) return;
174→
175→	if (!EdgeStartNode)
176→	{
177→		// 第一次点击：记录起点
178→		EdgeStartNode = Node;
179→		EdgeStartNode->SetHighlighted(true);
180→		UE_LOG(LogTemp, Log, TEXT("选择边起点: 节点 %d"), EdgeStartNode->NodeID);
181→	}
182→	else
183→	{
184→		// 第二次点击：创建边
185→		if (EdgeStartNode != Node)
186→		{
187→			Manager->AddEdge(EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
188→			UE_LOG(LogTemp, Log, TEXT("创建边: %d -> %d (消耗 %d 回合)"),
189→				EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
190→		}
191→
192→		// 清除高亮和状态
193→		EdgeStartNode->SetHighlighted(false);
194→		EdgeStartNode = nullptr;
195→	}
196→}
