198→void ULFPWorldMapEditorComponent::HandleEdgeRemoval(ALFPWorldMapNode* Node)
199→{
200→	if (!Node) return;
201→
202→	ALFPWorldMapManager* Manager = GetWorldMapManager();
203→	if (!Manager) return;
204→
205→	if (!EdgeRemovalStartNode)
206→	{
207→		// 第一次点击：记录起点
208→		EdgeRemovalStartNode = Node;
209→		EdgeRemovalStartNode->SetHighlighted(true);
210→		UE_LOG(LogTemp, Log, TEXT("选择要删除的边起点: 节点 %d"), EdgeRemovalStartNode->NodeID);
211→	}
212→	else
213→	{
214→		// 第二次点击：删除边
215→		if (EdgeRemovalStartNode != Node)
216→		{
217→			bool bRemoved = Manager->RemoveEdge(EdgeRemovalStartNode->NodeID, Node->NodeID);
218→			if (bRemoved)
219→			{
220→				UE_LOG(LogTemp, Log, TEXT("删除边: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
221→			}
222→			else
223→			{
224→				UE_LOG(LogTemp, Warning, TEXT("边不存在: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
225→			}
226→		}
227→
228→		// 清除高亮和状态
229→		EdgeRemovalStartNode->SetHighlighted(false);
230→		EdgeRemovalStartNode = nullptr;
231→	}
232→}
