234→void ULFPWorldMapEditorComponent::MoveSelectedNodeTo(FVector2D NewPos)
235→{
236→	if (!SelectedNode) return;
237→
238→	SelectedNode->SetPosition2D(NewPos);
239→
240→	// 更新所有关联边的视觉位置
241→	ALFPWorldMapManager* Manager = GetWorldMapManager();
242→	if (!Manager) return;
243→
244→	TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(SelectedNode->NodeID);
245→	for (ALFPWorldMapNode* Neighbor : Neighbors)
246→	{
247→		if (ALFPWorldMapEdge* Edge = Manager->GetEdge(SelectedNode->NodeID, Neighbor->NodeID))
248→		{
249→			Edge->UpdateVisualPosition(SelectedNode->GetActorLocation(), Neighbor->GetActorLocation());
250→		}
251→	}
252→
253→	UE_LOG(LogTemp, Log, TEXT("移动节点 %d 到 (%.1f, %.1f)"), SelectedNode->NodeID, NewPos.X, NewPos.Y);
254→}
