270→void ULFPWorldMapEditorComponent::EnterBattleMapEditor()
271→{
272→	if (!SelectedNode)
273→	{
274→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 未选中节点"));
275→		return;
276→	}
277→
278→	if (SelectedNode->NodeType != ELFPWorldNodeType::WNT_Battle)
279→	{
280→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 选中的不是战斗节点"));
281→		return;
282→	}
283→
284→	if (SelectedNode->BattleMapName.IsEmpty())
285→	{
286→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 战斗地图名称为空"));
287→		return;
288→	}
289→
290→	// 获取战斗地图编辑器组件（在同一个 PlayerController 上）
291→	ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
292→	if (!BattleEditor)
293→	{
294→		UE_LOG(LogTemp, Error, TEXT("EnterBattleMapEditor: 找不到战斗地图编辑器组件"));
295→		return;
296→	}
297→
298→	// 加载战斗地图
299→	bool bLoaded = BattleEditor->LoadMap(SelectedNode->BattleMapName);
300→	if (!bLoaded)
301→	{
302→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 加载战斗地图失败，创建新地图"));
303→		BattleEditor->NewMap(10, 10);
304→	}
305→
306→	// 激活战斗地图编辑器
307→	if (!BattleEditor->IsEditorActive())
308→	{
309→		BattleEditor->ToggleEditorMode();
310→	}
311→
312→	bIsEditingBattleMap = true;
313→	UE_LOG(LogTemp, Log, TEXT("进入战斗地图编辑: %s"), *SelectedNode->BattleMapName);
314→}
