316→void ULFPWorldMapEditorComponent::ReturnFromBattleMapEditor()
317→{
318→	if (!bIsEditingBattleMap) return;
319→
320→	ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
321→	if (BattleEditor && SelectedNode)
322→	{
323→		// 保存战斗地图（自动关联回节点）
324→		BattleEditor->SaveMap(SelectedNode->BattleMapName);
325→
326→		// 关闭战斗地图编辑器
327→		if (BattleEditor->IsEditorActive())
328→		{
329→			BattleEditor->ToggleEditorMode();
330→		}
331→	}
332→
333→	bIsEditingBattleMap = false;
334→	UE_LOG(LogTemp, Log, TEXT("返回世界地图编辑器"));
335→}
